.item-name{display:block;color:var(--_text);font-size:15px;font-weight:750;letter-spacing:-.01em}
.item-note{display:block;max-width:190px;margin:5px auto 0;color:var(--_muted);font-size:12px;font-weight:500;line-height:1.35}
.ribbon{display:inline-flex;align-items:center;margin-bottom:8px;padding:3px 8px;border-radius:999px;background:var(--_accent);color:#fff;font-size:9px;font-weight:850;letter-spacing:.09em;line-height:1.4;text-transform:uppercase;box-shadow:0 4px 10px color-mix(in srgb,var(--_accent) 25%,transparent)}
.feature{position:sticky;left:0;z-index:2;min-width:220px;max-width:280px;background:var(--_raised);color:var(--_text);font-weight:650;text-align:left;box-shadow:1px 0 0 var(--_line)}
td.recommended{background:var(--_accent-soft)}
tbody tr.data-row:hover th,tfoot tr:hover th{background:var(--_hover)}
tbody tr.data-row:hover td{background:var(--_hover)}
tbody tr.data-row:hover td.recommended{background:color-mix(in srgb,var(--_accent) 13%,var(--_bg))}
.group-row th,.group-row td{padding-top:9px;padding-bottom:9px;background:var(--_group);border-bottom:1px solid var(--_line)}
.group-label{position:sticky;left:0;z-index:2;min-width:220px;color:var(--_muted);font-size:10px;font-weight:850;letter-spacing:.12em;text-align:left;text-transform:uppercase;box-shadow:1px 0 0 var(--_line)}
.group-fill{height:35px}
.mark{display:inline-flex;min-width:28px;height:28px;align-items:center;justify-content:center;border-radius:999px;font-size:16px;font-weight:850;line-height:1}
.mark.yes{background:color-mix(in srgb,var(--_ok) 12%,var(--_bg));color:var(--_ok)}
.mark.no{background:color-mix(in srgb,var(--_no) 11%,var(--_bg));color:var(--_no)}
.mark.partial{min-width:auto;padding:0 10px;background:color-mix(in srgb,var(--_partial) 13%,var(--_bg));color:var(--_partial);font-size:11px;letter-spacing:.02em}
.rating{display:inline-flex;align-items:baseline;gap:6px;font-weight:750}
.star{color:#f59e0b;font-size:15px}
.out-of{color:var(--_muted);font-size:11px;font-weight:600}
.text-value{display:inline-block;max-width:220px;color:var(--_text);overflow-wrap:anywhere}
.empty{padding:42px 24px;color:var(--_muted);font-size:14px;text-align:center}
@media (max-width:520px){.heading{padding:18px 18px 16px}th,td{padding:12px 14px;min-width:142px}.feature,.group-label,thead .corner{min-width:176px;max-width:210px}}
@media (prefers-color-scheme:dark){:host{--_bg:var(--ov-bg,#0f172a);--_raised:var(--ov-bg,#111827);--_text:var(--ov-text,#e5e7eb);--_muted:var(--ov-muted,#9ca3af);--_line:var(--ov-line,#293548);--_accent:var(--ov-accent,#818cf8);--_ok:var(--ov-ok,#34d399);--_no:var(--ov-no,#fb7185);--_partial:var(--ov-partial,#fbbf24);--_soft:#111827;--_group:#182235;--_accent-soft:#1b2145;--_hover:#172033}.frame{box-shadow:0 14px 34px rgba(0,0,0,.28)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(CSS); root.adoptedStyleSheets=[sheet];
const make = (tag,className,text) => { const node=document.createElement(tag); if(className) node.className=className; if(text!==undefined) node.textContent=text; return node; };
const items=Array.isArray(data.items)?data.items:[];
const features=Array.isArray(data.features)?data.features:[];
const cells=Array.isArray(data.cells)?data.cells:[];
const title=typeof data.title==='string'&&data.title.trim()?data.title.trim():'Comparison';
const frame=make('section','frame'); frame.setAttribute('aria-label',title);
const heading=make('header','heading');
heading.appendChild(make('div','eyebrow','Comparison matrix'));
heading.appendChild(make('h2','',title));
heading.appendChild(make('div','meta',items.length+' option'+(items.length===1?'':'s')+' · '+features.length+' criteria'));
frame.appendChild(heading);
if(!items.length||!features.length){
  frame.appendChild(make('div','empty','Add at least one item and one feature to build the comparison.'));
}else{
  const scroll=make('div','scroll');
  const table=make('table'); table.appendChild(make('caption','sr-only',title));
  const thead=make('thead'); const headerRow=make('tr');
  const corner=make('th','corner','Features'); corner.scope='col'; headerRow.appendChild(corner);
  items.forEach((item) => {
    const highlighted=item&&item.highlight===true;
    const th=make('th','item-head'+(highlighted?' recommended':'')); th.scope='col';
    if(highlighted) th.appendChild(make('span','ribbon','Recommended'));
    th.appendChild(make('span','item-name',item&&item.name!=null?String(item.name):'Untitled'));
    if(item&&item.note) th.appendChild(make('span','item-note',String(item.note)));
    headerRow.appendChild(th);
  });
  thead.appendChild(headerRow); table.appendChild(thead);
  const tbody=make('tbody'); let previousGroup=null;
  features.forEach((feature,featureIndex) => {
    const group=feature&&typeof feature.group==='string'?feature.group.trim():'';
    if(group&&group!==previousGroup){
      const groupRow=make('tr','group-row');
      const groupLabel=make('th','group-label',group); groupLabel.scope='rowgroup'; groupRow.appendChild(groupLabel);
      const groupFill=make('td','group-fill'); groupFill.colSpan=items.length; groupFill.setAttribute('aria-hidden','true'); groupRow.appendChild(groupFill);
      tbody.appendChild(groupRow);
    }
    previousGroup=group;
    const row=make('tr','data-row');
    const featureLabel=make('th','feature',feature&&feature.label!=null?String(feature.label):'Untitled feature'); featureLabel.scope='row'; row.appendChild(featureLabel);
    const kind=feature&&feature.kind?feature.kind:'text';
    const rowCells=Array.isArray(cells[featureIndex])?cells[featureIndex]:[];
    items.forEach((item,itemIndex) => {
      const td=make('td',item&&item.highlight===true?'recommended':'');
      const value=rowCells[itemIndex];
      if(kind==='bool'){
        if(value===true){ const mark=make('span','mark yes','✓'); mark.setAttribute('aria-label','Yes'); td.appendChild(mark); }
        else if(value===false){ const mark=make('span','mark no','✗'); mark.setAttribute('aria-label','No'); td.appendChild(mark); }
        else if(value==='partial'){ const mark=make('span','mark partial','Partial'); mark.setAttribute('aria-label','Partially supported'); td.appendChild(mark); }
        else td.appendChild(make('span','text-value','—'));
      }else if(kind==='rating'){
        if(typeof value==='number'&&Number.isFinite(value)){
          const score=Math.max(0,Math.min(5,value)); const rating=make('span','rating'); rating.setAttribute('aria-label',score+' out of 5');
          rating.appendChild(make('span','star','★')); rating.appendChild(make('span','',Number.isInteger(score)?String(score):score.toFixed(1))); rating.appendChild(make('span','out-of','/ 5')); td.appendChild(rating);
        }else td.appendChild(make('span','text-value','—'));
      }else{
        const display=value===null||value===undefined||value===''?'—':String(value); td.appendChild(make('span','text-value',display));
      }
      row.appendChild(td);
    });
    tbody.appendChild(row);
  });
  table.appendChild(tbody); scroll.appendChild(table); frame.appendChild(scroll);
}
root.appendChild(frame);
parent.appendChild(host);
